<?php $page_title='Danh mục';require __DIR__.'/_layout_start.php';require_once __DIR__.'/../models/AdminCatalog.php';$m=new AdminCatalog(db_connect());$edit=(int)($_GET['edit']??0);$row=$edit?($m->findCategory($edit)):null;if(is_post()){$id=(int)($_POST['id']??0); if('categories.php'==='categories.php')$m->saveCategory(['ten_danh_muc'=>$_POST['name'],'trang_thai'=>$_POST['trang_thai']],$id); else $m->saveBrand(['ten_danh_muc'=>$_POST['name'],'trang_thai'=>$_POST['trang_thai']],$id); redirect('admin/categories.php');}$rows=$m->categories();?><h1>Danh mục</h1><div class="row"><div class="col-md-4"><form method="post" class="bg-white p-4 rounded-4"><input type="hidden" name="id" value="<?=h($row['id_danh_muc']??0)?>"><input name="name" class="form-control mb-2" value="<?=h($row['ten_danh_muc']??'')?>" placeholder="Tên"><select name="trang_thai" class="form-select mb-2"><option value="hien">Hiện</option><option value="an">Ẩn</option></select><button class="btn btn-primary">Lưu</button></form></div><div class="col-md-8"><div class="bg-white p-4 rounded-4"><table class="table"><?php foreach($rows as $r):?><tr><td><?=h($r['ten_danh_muc'])?></td><td><?=h($r['trang_thai'])?></td><td><a href="<?=BASE_URL?>/admin/categories.php?edit=<?=$r['id_danh_muc']?>" class="btn btn-sm btn-outline-primary">Sửa</a></td></tr><?php endforeach;?></table></div></div></div><?php require __DIR__.'/_layout_end.php';?>
